import{_ as a,o as t,c as p,j as r,a as b,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const P=JSON.parse('{"title":"【武学基础】","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/武技类/武学基础/【武学基础】.md","filePath":"4.资源分区/6.技艺及称号/武技类/武学基础/【武学基础】.md"}'),s={name:"4.资源分区/6.技艺及称号/武技类/武学基础/【武学基础】.md"};function o(d,e,_,l,i,c){return t(),p("div",null,[...e[0]||(e[0]=[r("h1",{id:"【武学基础】",tabindex:"-1"},[b("【武学基础】 "),r("a",{class:"header-anchor",href:"#【武学基础】","aria-label":'Permalink to "【武学基础】"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新秩序007")])])],-1),n('<h1 id="武学基础" tabindex="-1">武学基础 <a class="header-anchor" href="#武学基础" aria-label="Permalink to &quot;武学基础&quot;">​</a></h1><p>武学基础<br> 只有获得了武学基础才能运用武学总纲的能力，学习武学基础可以支付经验从下列内容中选择修行，特殊的，正常人无法拥有属性为相克的内力。</p><p>火行<br> 6XP<br> 磨炼修行：每场影片结束后，若你修行了火行，则可以在主神空间支付4XP，以减少2点火行内力带来的亢奋点数。<br> 当人物的最高支线等级到达C/B/A/S时，火行将自动升级到对应等级。</p><p>水行<br> 6XP<br> 磨炼修行：每场影片结束后，若你修行了水行，则可以在主神空间支付2XP，以再获得1点作用在攻击上的高速点数。<br> 当人物的最高支线等级到达C/B/A/S时，水行将自动升级到对应等级。</p><p>木行<br> 6XP<br> 当人物的最高支线等级到达C/B/A/S时，木行将自动升级到对应等级。</p><p>金行<br> 6XP<br> 磨炼修行：每场影片结束后，若你修行了金行，则可以在主神空间支付6XP，以减少2点作用于自身的剧痛点数。<br> 当人物的最高支线等级到达C/B/A/S时，金行将自动升级到对应等级。</p><p>土行<br> 12XP<br> 磨炼修行：每场影片结束后，若你修行了木行，则可以在主神空间支付2XP，以再获得1点强韧上的检定加值。<br> 当人物的最高支线等级到达C/B/A/S时，土行将自动升级到对应等级。</p><p>阴性内力<br> 6XP<br> 磨炼修行：当人物的最高支线等级到达C/B/A/S时，阴性内力将自动升级到对应等级。</p><p>阳性内力<br> 6XP<br> 磨炼修行：当人物的最高支线等级到达C/B/A/S时，阳性内力将自动升级到对应等级。</p><p>战技入门<br> 9XP<br> 在修行战技入门后，才可以掌握武学总纲中战技的用法，享受对应好处。</p><p>步法入门<br> 9XP<br> 在修行步法入门后，才可以掌握武学总纲中步法的用法，享受对应好处。</p><p>身法入门<br> 9XP<br> 在修行身法入门后，才可以掌握武学总纲中身法的用法，享受对应好处。</p><hr><p>Copyright ? 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',14)])])}const X=a(s,[["render",o]]);export{P as __pageData,X as default};
